#include "interface.h"

#include <stdint.h>
#include <stddef.h>

uint64_t run(const int32_t* deltas, size_t count, int iters) {
  uint64_t total = 0;

  for (int iter = 0; iter < iters; ++iter) {
    const int32_t* p = deltas;
    size_t n = count;
    int64_t current = 0;
    uint64_t sum = 0;

    while (n >= 8) {
      current += (int64_t)p[0];
      sum += (uint64_t)(current + 0x9E3779B1LL);
      current += (int64_t)p[1];
      sum += (uint64_t)(current + 0x9E3779B1LL);
      current += (int64_t)p[2];
      sum += (uint64_t)(current + 0x9E3779B1LL);
      current += (int64_t)p[3];
      sum += (uint64_t)(current + 0x9E3779B1LL);
      current += (int64_t)p[4];
      sum += (uint64_t)(current + 0x9E3779B1LL);
      current += (int64_t)p[5];
      sum += (uint64_t)(current + 0x9E3779B1LL);
      current += (int64_t)p[6];
      sum += (uint64_t)(current + 0x9E3779B1LL);
      current += (int64_t)p[7];
      sum += (uint64_t)(current + 0x9E3779B1LL);
      p += 8;
      n -= 8;
    }

    while (n--) {
      current += (int64_t)(*p++);
      sum += (uint64_t)(current + 0x9E3779B1LL);
    }

    total = sum;
  }

  return total;
}
